const keywords = [
  "looking for automation",
  "need automation",
  "n8n developer",
 "workflow automation",
  "AI automation"
];

return keywords.map(k => ({ json: { keyword: k } }));

// Normalizes whatever field names your chosen Apify actor returns
// into a stable shape used by every downstream node.
// EDIT the right-hand fallback field names to match your actor's real output
// (check one raw execution in n8n to see actual keys).

const keywordUsed = $('Set Keywords List').item.json.keyword;

return items.map(item => {
  const d = item.json;
  return {
    json: {
      postText: d.text || d.postText || d.message || "",
      postUrl: d.url || d.postUrl || d.link || "",
      authorName: d.authorName || (d.user && d.user.name) || d.author || "Unknown",
      authorProfileUrl: d.authorUrl || (d.user && d.user.url) || "",
      postDate: d.time || d.postDate || d.timestamp || new Date().toISOString(),
      sourceName: d.groupTitle || d.pageTitle || "Facebook",
      matchedKeyword: keywordUsed
    }
  };
});

// Filters out posts older than 7 days
const now = new Date();
const sevenDaysMs = 1000 * 24 * 60 * 60 * 1000;

return items.filter(item => {
  const postDate = new Date(item.json.postDate);
  if (isNaN(postDate.getTime())) return true; // keep if date unparseable, don't silently drop
  const ageMs = now.getTime() - postDate.getTime();
  return ageMs < sevenDaysMs;
});

// Strip tracking params so the same post doesn't look 'new' on re-scrape
return items.map(item => {
  const rawUrl = item.json.postUrl || "";
  const normalized = rawUrl.split('?')[0];
  return { json: { ...item.json, postUrlNormalized: normalized } };
});

const originalItems = $('Normalize Post URL').all();

// Build a Set of URLs that WERE found in the sheet (i.e., duplicates)
const matchedUrls = new Set(
  items.map(i => i.json['Post link']).filter(Boolean)
);

return originalItems.map(orig => {
  const isDup = matchedUrls.has(orig.json.postUrlNormalized);
  return { json: { ...orig.json, isDuplicate: isDup } };
});

