const originalItems = $('Parse Gemini Extraction Response').all();

return items.map((item, index) => {
  const original = originalItems[index] ? originalItems[index].json : {};

  let parsed;
  try {
    const raw = item.json.choices[0].message.content;
    parsed = JSON.parse(raw);
  } catch (e) {
    parsed = { comment_reply: "PARSE_ERROR - write manually", dm_reply: "PARSE_ERROR - write manually" };
  }

  return {
    json: {
      postText: original.postText || "",
      postUrl: original.postUrl || "",
      postUrlNormalized: original.postUrlNormalized || "",
      authorName: original.authorName || "Unknown",
      authorProfileUrl: original.authorProfileUrl || "",
      postDate: original.postDate || "",
      sourceName: original.sourceName || "Facebook",
      matchedKeyword: original.matchedKeyword || "",
      intent: original.intent,
      industry: original.industry,
      pain_point: original.pain_point,
      lead_score: original.lead_score,
      confidence: original.confidence,
      reasoning: original.reasoning,
      comment_reply: parsed.comment_reply,
      dm_reply: parsed.dm_reply
    }
  };
});

return items.map(item => {
  const postText = (item.json.postText || "").replace(/"/g, "'").replace(/\n/g, " ");

  const prompt = `You are a lead qualification analyst for a freelance AI automation developer named Muhammad Sohaib (Averic Labs). Analyze this Facebook post and respond ONLY with valid JSON, no markdown, no preamble.

Post text: "${postText}"

Return this exact JSON structure:
{
  "intent": "hiring | asking_advice | venting | spam | unclear",
  "industry": "best guess industry or 'unknown'",
  "pain_point": "one sentence describing their core problem",
  "lead_score": integer 1-10,
  "confidence": integer 1-10,
  "reasoning": "one short sentence why you scored it this way"
}

Scoring guide:
- 9-10: explicitly hiring, budget mentioned, urgent need
- 6-8: clear problem described, open to solutions, no budget stated
- 3-5: vague interest or general automation discussion
- 1-2: spam, unrelated, or someone else answering (not the lead)`;

  return { json: { ...item.json, geminiPrompt: prompt } };
});

